+function convertMarkdownLinks(text: string, convertLinks: boolean, convertImages: boolean): string {
+  if (!convertLinks && !convertImages) return text;
+  let result = '';
+  let index = 0;
+  while (index < text.length) {
+    const parsed = parseMarkdownLink(text, index);
+    if (!parsed) {
+      result += text[index++];
+      continue;
+    }
+    const {end, isImage, label, target} = parsed;
+    if ((isImage && !convertImages) || (!isImage && !convertLinks) || target.includes('://')) {
+      result += text.slice(index, end);
+      index = end;
+      continue;
+    }
+    const display = unescapeMarkdown(label);
+    const wikiTarget = unescapeMarkdown(target);
+    if (isImage) {
+      result += `![[${wikiTarget}${display === '' || display === wikiTarget ? '' : `|${display}`}]]`;
+    } else {
+      result += `[[${wikiTarget}${display === wikiTarget || display === getDefaultHeadingDisplay(wikiTarget) ? '' : `|${display}`}]]`;
+    }
+    index = end;
+  }
+  return result;
+}
+
+type ParsedMarkdownLink = {end: number, isImage: boolean, label: string, target: string};
+
+function parseMarkdownLink(text: string, start: number): ParsedMarkdownLink | null {
+  const isImage = text[start] === '!';
+  const labelStart = start + (isImage ? 1 : 0);
+  if (text[labelStart] !== '[' || text[labelStart + 1] === '[') return null;
+  const labelEnd = findBalancedEnd(text, labelStart, '[', ']');
+  if (labelEnd === -1 || text[labelEnd + 1] !== '(') return null;
+  const close = findDestinationEnd(text, labelEnd + 2);
+  if (!close) return null;
+  const label = text.slice(labelStart + 1, labelEnd);
+  const rawArea = text.slice(labelEnd + 2, close.end);
+  if (label.includes('\
') || rawArea.includes('\
')) return null;
+  const target = parseDestination(rawArea);
+  return target === null ? null : {end: close.end + 1, isImage, label, target};
+}
+
+function findBalancedEnd(text: string, start: number, open: string, close: string): number {
+  let depth = 0;
+  for (let i = start; i < text.length; i++) {
+    if (text[i] === '\\\') {
+      i++;
+    } else if (text[i] === open) {
+      depth++;
+    } else if (text[i] === close && --depth === 0) {
+      return i;
+    }
+  }
+  return -1;
+}
+
+function findDestinationEnd(text: string, start: number): {end: number} | null {
+  let depth = 0;
+  for (let i = start; i < text.length; i++) {
+    if (text[i] === '\\\') {
+      i++;
+    } else if (text[i] === '(') {
+      depth++;
+    } else if (text[i] === ')' && depth-- === 0) {
+      return {end: i};
+    }
+  }
+  return null;
+}
+
+function parseDestination(area: string): string | null {
+  const trimmed = area.trim();
+  if (trimmed.startsWith('<')) {
+    const end = findUnescapedCharacter(trimmed, '>', 1);
+    return end !== -1 && trimmed.slice(end + 1).trim() === '' ? trimmed.slice(1, end) : null;
+  }
+  // Unescaped whitespace after a destination introduces a Markdown title.
+  for (let i = 0; i < trimmed.length; i++) {
+    if (trimmed[i] === '\\\') {
+      i++;
+    } else if (/\\s/.test(trimmed[i])) {
+      return null;
+    }
+  }
+  return trimmed;
+}
+
+function findUnescapedCharacter(text: string, character: string, start: number): number {
+  for (let i = start; i < text.length; i++) {
+    if (text[i] === '\\\') i++;
+    else if (text[i] === character) return i;
+  }
+  return -1;
+}
+
+function unescapeMarkdown(value: string): string {
+  return value.replace(/\\\\(.)/g, '$1');
+}
+
+function getDefaultHeadingDisplay(target: string): string {
+  const hash = target.indexOf('#');
+  if (hash === -1) return target;
+  const page = target.slice(0, hash);
+  const heading = target.slice(hash + 1);
+  return page ? `${page} > ${heading}` : heading;
+}
